import { performance } from 'node:perf_hooks';

import {
  compileGgTopologyToGrassmannianCache,
  decideGgGrassmannianCacheSkip,
  diffGgGrassmannianCachePlans,
} from '../../src/betty/gg-grassmannian-cache';
import { Pipeline, prefixHashU64 } from '../src/pipeline';
import type { IStation } from '../src/types';

const HIDDEN_DIM = Number(process.env['GNOSIS_AMPH_BENCH_HIDDEN'] ?? 256);
const PROMPT_LEN = Number(process.env['GNOSIS_AMPH_BENCH_PROMPT'] ?? 128);
const ITERATIONS = Number(process.env['GNOSIS_AMPH_BENCH_ITERATIONS'] ?? 100);
const WARMUP = Number(process.env['GNOSIS_AMPH_BENCH_WARMUP'] ?? 10);
const STATIONS = 3;

const FANOUT_TOPOLOGY = `
  (entry_0: Entry:DistributedInference { module: 'monster', function: 'prefill' })
  (station_0: Station:FoilBranch { layer_lo: 0, layer_hi: 4 })
  (station_1: Station:FoilBranch { layer_lo: 4, layer_hi: 8 })
  (station_2: Station:FoilBranch { layer_lo: 8, layer_hi: 12 })
  (lm_head: Exit:FoilJoin { role: 'lm_head' })
  (entry_0)-[:FORK { family: 'AmplituhedronReplay' }]->(station_0 | station_1 | station_2)
  (station_0 | station_1 | station_2)-[:FOLD { family: 'AmplituhedronReplay' }]->(lm_head)
`;

const FANOUT_TOPOLOGY_MUTATED = FANOUT_TOPOLOGY.replace('layer_hi: 8', 'layer_hi: 9');

interface CachedVolume {
  prefixHash: string;
  prefixLen: number;
  tailResidual: Float32Array;
  prefixResidual: Float32Array;
}

interface BenchStation {
  station: IStation;
  cache: CachedVolume[];
  counters: {
    embeds: number;
    forwards: number;
    replays: number;
    captures: number;
    lmHeads: number;
  };
}

function makePrompt(seed: number): Uint32Array {
  const out = new Uint32Array(PROMPT_LEN);
  for (let i = 0; i < out.length; i++) out[i] = 1000 + ((seed + i * 17) % 4096);
  return out;
}

async function prefixHashU64ForcedCopyForBench(tokens: Uint32Array): Promise<string> {
  const crypto = (globalThis as typeof globalThis & { crypto?: Crypto }).crypto;
  if (!crypto?.subtle) return await prefixHashU64(tokens);

  const bytesIn = new Uint8Array(tokens.byteLength);
  bytesIn.set(new Uint8Array(tokens.buffer, tokens.byteOffset, tokens.byteLength));
  const digest = await crypto.subtle.digest('SHA-256', bytesIn);
  const bytes = new Uint8Array(digest);
  let h = 0n;
  for (let i = 0; i < 8; i++) {
    h = (h << 8n) | BigInt(bytes[i]!);
  }
  return h.toString();
}

function assembleOutputArrayPath(prompt: Uint32Array, count: number): Uint32Array {
  const out: number[] = Array.from(prompt);
  for (let i = 0; i < count; i++) out.push((i + 7) >>> 0);
  return new Uint32Array(out);
}

function assembleOutputPreallocPath(prompt: Uint32Array, count: number): Uint32Array {
  const out = new Uint32Array(prompt.length + count);
  out.set(prompt);
  for (let i = 0; i < count; i++) out[prompt.length + i] = (i + 7) >>> 0;
  return out;
}

function copyTail(prefixResidual: Float32Array): Float32Array {
  return prefixResidual.slice(prefixResidual.length - HIDDEN_DIM);
}

function makeStation(index: number): BenchStation {
  const cache: CachedVolume[] = [];
  const counters = { embeds: 0, forwards: 0, replays: 0, captures: 0, lmHeads: 0 };
  const station = {
    startLayer: index * 4,
    endLayer: index * 4 + 4,
    role: index === 0 ? 'entry' : index === STATIONS - 1 ? 'exit' : 'mid',
    maxBatchSize: 32,

    async embed({ tokens }: { tokens: Uint32Array; startPos: number; requestId?: string }) {
      counters.embeds++;
      const out = new Float32Array(tokens.length * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) {
        out[i] = ((tokens[Math.floor(i / HIDDEN_DIM)] ?? 0) + (i % HIDDEN_DIM)) * 0.0001;
      }
      return out;
    },

    async forward({
      residual,
      sequenceLength,
    }: {
      residual: Float32Array;
      startPos: number;
      sequenceLength: number;
      requestId?: string;
    }) {
      counters.forwards++;
      const out = new Float32Array(sequenceLength * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) {
        let v = residual[i] ?? 0;
        for (let round = 0; round < 8; round++) v = Math.fround(v * 1.00001 + 0.00001 * (index + 1));
        out[i] = v;
      }
      return { residual: out };
    },

    async lmHead() {
      counters.lmHeads++;
      const logits = new Float32Array(32);
      logits[7] = 1;
      return logits;
    },

    async cobordismEmbed() {
      throw new Error('not used');
    },
    async cobordismLmHead() {
      throw new Error('not used');
    },
    async bizarroForward() {
      return null;
    },

    async amplituhedronReplay({
      prefixHash,
      prefixLen,
    }: {
      prefixHash: string;
      prefixLen: number;
      layerLo: number;
      layerHi: number;
      requestId?: string;
    }) {
      counters.replays++;
      const hit = cache.find((entry) => entry.prefixHash === prefixHash && entry.prefixLen === prefixLen);
      if (!hit) return { hit: false };
      return {
        hit: true,
        tailResidual: hit.tailResidual,
        prefixResidual: hit.prefixResidual,
      };
    },

    async amplituhedronCapture({
      prefixHash,
      prefixLen,
      tailResidual,
    }: {
      prefixHash: string;
      prefixLen: number;
      layerLo: number;
      layerHi: number;
      tailResidual?: Float32Array;
      requestId?: string;
    }) {
      counters.captures++;
      if (!tailResidual || tailResidual.length !== prefixLen * HIDDEN_DIM) return;
      const prefixResidual = new Float32Array(tailResidual);
      cache.length = 0;
      cache.push({
        prefixHash,
        prefixLen,
        prefixResidual,
        tailResidual: copyTail(prefixResidual),
      });
    },
  } as IStation;
  return { station, cache, counters };
}

function makeMesh(): { pipeline: Pipeline; stations: BenchStation[] } {
  const stations = Array.from({ length: STATIONS }, (_, i) => makeStation(i));
  return {
    stations,
    pipeline: new Pipeline({
      stations: stations.map((s) => s.station),
      hiddenDim: HIDDEN_DIM,
      vocabSize: 32,
      chunkSize: 32,
      stopTokens: [],
    }),
  };
}

async function flushCaptures(): Promise<void> {
  await new Promise((resolve) => setTimeout(resolve, 0));
}

async function measure(label: string, fn: (i: number) => Promise<void>): Promise<number[]> {
  for (let i = 0; i < WARMUP; i++) await fn(i);
  const samples: number[] = [];
  for (let i = 0; i < ITERATIONS; i++) {
    const t0 = performance.now();
    await fn(i);
    samples.push((performance.now() - t0) * 1000);
  }
  samples.sort((a, b) => a - b);
  const mean = samples.reduce((a, b) => a + b, 0) / samples.length;
  const p50 = samples[Math.floor(samples.length * 0.5)] ?? 0;
  const p95 = samples[Math.floor(samples.length * 0.95)] ?? samples.at(-1) ?? 0;
  console.log(`${label.padEnd(22)} mean=${mean.toFixed(1)}us p50=${p50.toFixed(1)}us p95=${p95.toFixed(1)}us`);
  return samples;
}

async function main(): Promise<void> {
  console.log(`amplituhedron partial replay bench prompt=${PROMPT_LEN} hidden=${HIDDEN_DIM} iterations=${ITERATIONS}`);

  {
    const seed = compileGgTopologyToGrassmannianCache(FANOUT_TOPOLOGY, {
      chart: 'distributed-inference-app-cache',
      sourceId: 'monster-seed',
    });
    const sameCurrent = compileGgTopologyToGrassmannianCache(FANOUT_TOPOLOGY, {
      chart: 'distributed-inference-app-cache',
      sourceId: 'monster-current',
    });
    const changedCurrent = compileGgTopologyToGrassmannianCache(FANOUT_TOPOLOGY_MUTATED, {
      chart: 'distributed-inference-app-cache',
      sourceId: 'monster-current-mutated',
    });

    await measure('grassmannian-skip', async () => {
      const decision = decideGgGrassmannianCacheSkip(seed, sameCurrent);
      if (!decision.canSkip || decision.action !== 'skip-current-execution') {
        throw new Error(`unexpected Grassmannian skip decision: ${decision.action}`);
      }
    });

    await measure('grassmannian-diff', async () => {
      const diff = diffGgGrassmannianCachePlans(seed, changedCurrent);
      if (diff.defectRank !== 1) {
        throw new Error(`unexpected Grassmannian defect rank: ${diff.defectRank}`);
      }
    });
  }

  await measure('prefix-hash-u64', async (i) => {
    const hash = await prefixHashU64(makePrompt(i));
    if (!hash.length) throw new Error('empty prefix hash');
  });

  await measure('prefix-hash-copy', async (i) => {
    const hash = await prefixHashU64ForcedCopyForBench(makePrompt(i));
    if (!hash.length) throw new Error('empty prefix hash');
  });

  await measure('assemble-output-array', async (i) => {
    const out = assembleOutputArrayPath(makePrompt(i), 8);
    if (out.length !== PROMPT_LEN + 8) throw new Error('bad output length');
  });

  await measure('assemble-output-prealloc', async (i) => {
    const out = assembleOutputPreallocPath(makePrompt(i), 8);
    if (out.length !== PROMPT_LEN + 8) throw new Error('bad output length');
  });

  await measure('cold-prefill', async (i) => {
    const { pipeline } = makeMesh();
    await pipeline.generate({ promptTokens: makePrompt(i), maxNewTokens: 0 });
    await flushCaptures();
  });

  await measure('prefill-no-capture', async (i) => {
    const { pipeline } = makeMesh();
    await pipeline.pipelinedPrefill({
      promptTokens: makePrompt(i),
      computeLogits: false,
    });
  });

  await measure('prefill-capture-resids', async (i) => {
    const { pipeline } = makeMesh();
    const prefill = await pipeline.pipelinedPrefill({
      promptTokens: makePrompt(i),
      computeLogits: false,
      captureStationResiduals: true,
    });
    if (!prefill.stationPrefixResiduals) {
      throw new Error('expected captured station residuals');
    }
  });

  await measure('generate-8-tokens', async (i) => {
    const { pipeline } = makeMesh();
    await pipeline.generate({
      promptTokens: makePrompt(i),
      maxNewTokens: 8,
    });
  });

  {
    const { pipeline } = makeMesh();
    const prompt = makePrompt(1);
    await pipeline.generate({ promptTokens: prompt, maxNewTokens: 0 });
    await flushCaptures();
    await measure('full-replay-hit', async () => {
      await pipeline.generate({ promptTokens: prompt, maxNewTokens: 0 });
    });
  }

  {
    const { pipeline, stations } = makeMesh();
    const prompt = makePrompt(2);
    await pipeline.generate({ promptTokens: prompt, maxNewTokens: 0 });
    await flushCaptures();
    await measure('partial-replay-suffix', async () => {
      stations[1]!.cache.length = 0;
      stations[2]!.cache.length = 0;
      await pipeline.generate({ promptTokens: prompt, maxNewTokens: 0 });
      await flushCaptures();
    });
  }
}

await main();
